  ('pukao-d592fc58-moex-00152', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '假設一消費者之效用函數為U(X,Y)=aX+bY(a>0且b>0)，兩財貨的價格分別為P =1與P =2，若其效 X Y 用極大化時，消費者將所得全用於購買X，請問參數a與b應滿足下列那個條件？', '["2a>b", "2a<b", "a>2b", "a<2b"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
